css:
.loader {
      position: relative;
      display: inline-block;
      width: 48px;
      height: 48px;
      border-radius: 50%;
      border: 1px solid color-mix(in srgb, var(--loader-color) 24%, transparent);
    }
    .loader i {
      position: absolute;
      inset: -3px;
      border-radius: 50%;
      animation: orbit 1.2s linear infinite;
    }
    .loader i::before {
      content: "";
      position: absolute;
      top: 0;
      left: 50%;
      width: 10px;
      height: 10px;
      margin-left: -5px;
      border-radius: 50%;
      background: var(--loader-color);
      box-shadow: 0 0 18px color-mix(in srgb, var(--loader-color) 45%, transparent);
    }
    .loader i:nth-child(1) { animation-delay: 0.00s; }
.loader i:nth-child(2) { animation-delay: -0.60s; }
    @keyframes orbit { to { transform: rotate(360deg); } }
